import scala.collection.mutable.HashMap
import scala.collection.mutable.ArrayBuffer

def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  val n = nums.length
  val ans = ArrayBuffer[Long]()

  for (query <- queries) {
    val (l, r, threshold) = (query(0).toLong, query(1).toLong, query(2).toLong)
    val freq = HashMap[Long, Int]()

    for (i <- l.toInt until r.toInt + 1) {
      val num = nums(i.toInt)
      freq(num) = freq.getOrElse(num, 0) + 1
    }

    var result = -1L
    var maxFreq = 0

    for ((num, count) <- freq.toList) {
      if (count >= threshold && count > maxFreq) {
        maxFreq = count
        result = num
      } else if (count >= threshold && count == maxFreq) {
        if (num < result) {
          result = num
        }
      }
    }

    ans += result
  }

  ans.toArray
}
