def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  val n = nums.length
  val ans = Array.ofDim[Long](queries.length)

  // Preprocess the array to create a list of (value, count) pairs for each index
  val freqMap = Array.ofDim[Map[Long, Int]](n)
  for (i <- 0 until n) {
    val map = scala.collection.mutable.HashMap[Long, Int]()
    for (j <- i until n) {
      val num = nums(j)
      map(num) = map.getOrElse(num, 0) + 1
      freqMap(i) = map.toMap
    }
  }

  for (i <- 0 until queries.length) {
    val (l, r, threshold) = (queries(i)(0), queries(i)(1), queries(i)(2))
    val subArrayFreq = freqMap(l)
    val candidates = subArrayFreq.filter { case (num, count) => count >= threshold }

    if (candidates.isEmpty) {
      ans(i) = -1
    } else {
      // Find the element with the highest frequency, and smallest value in case of tie
      val maxFreq = candidates.values.max
      val maxElements = candidates.filter { case (num, count) => count == maxFreq }
      val minNum = maxElements.keys.min
      ans(i) = minNum
    }
  }

  ans
}
